-- 0086_warehouses_company_id.sql — Phase 2 prep: add company_id to scm.warehouses (per-company) so 2990 warehouses migrate + inventory/grn FKs resolve. Nullable, backfill HOUZS, idempotent.
DO $$ BEGIN IF EXISTS (SELECT 1 FROM pg_class c JOIN pg_namespace n ON n.oid=c.relnamespace WHERE n.nspname='scm' AND c.relname='warehouses' AND c.relkind IN ('r','p')) THEN ALTER TABLE scm.warehouses ADD COLUMN IF NOT EXISTS company_id bigint; UPDATE scm.warehouses SET company_id=(SELECT id FROM public.companies WHERE code='HOUZS') WHERE company_id IS NULL; CREATE INDEX IF NOT EXISTS idx_warehouses_company_id ON scm.warehouses (company_id); END IF; END $$;
